        score = -d_self + 0.15 * d_opp + res_bonus
        moves.append((score, dx, dy))
    if not moves:
        return [0, 0]
    moves.sort(key=lambda t: (-t[0], t[1], t[2]))
    return [moves[0][1], moves[0][2]]
